# Tool definitions — each maps to a runbook action
tools = [
    {
        "name": "query_pod_logs",
        "description": "Fetch recent logs for a Kubernetes pod. Returns last N lines.",
        "input_schema": {
            "type": "object",
            "properties": {
                "namespace": {"type": "string"},
                "pod_name": {"type": "string"},
                "lines": {"type": "integer", "default": 100},
            },
            "required": ["namespace", "pod_name"],
        },
    },
    {
