        "description": "Create an incident ticket in JIRA with summary, description, and priority.",
        "input_schema": {
            "type": "object",
            "properties": {
                "summary": {"type": "string"},
                "description": {"type": "string"},
                "priority": {"type": "string", "enum": ["Low","Medium","High","Critical"]},
            },
            "required": ["summary", "description", "priority"],
        },
    },
]

def execute_tool(tool_name: str, tool_input: dict) -> str:
    """Stub implementations — replace with real kubectl / JIRA SDK calls."""
    if tool_name == "query_pod_logs":
        return f"[STUB] Last logs for {tool_input['pod_name']}: OOMKilled exit code 137"
    if tool_name == "restart_pod":
        return f"[STUB] Pod {tool_input['pod_name']} deleted; controller is recreating."
    if tool_name == "create_jira_ticket":
        return f"[STUB] Created ticket IT-1234: {tool_input['summary']}"
    return "Unknown tool"

def run_it_ops_agent(alert: dict) -> str:
    """Run the IT Ops agentic loop for a single alert."""
    system = (
        "You are an IT Ops agent. When given an alert, you: "
        "(1) diagnose the root cause using available tools, "
        "(2) execute Tier-0 remediation autonomously, "
        "(3) create a JIRA ticket documenting what you found and did. "
        "Always verify recovery after remediation."
    )
    messages = [
        {"role": "user", "content": f"Alert received: {json.dumps(alert)}"}
    ]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=2048,
            system=system,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            # Extract final text
            for block in response.content:
                if block.type == "text":
                    return block.text
            return "Done"

        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})

