import os
import time
import anthropic

TIER_0_ACTIONS = {"restart_pod", "flush_cache", "acknowledge_alert"}
TIER_1_ACTIONS = {"apply_terraform", "scale_database", "rotate_secret"}

client = anthropic.Anthropic()

def request_human_approval(action: str, params: dict, context: str) -> bool:
    """
    Post an approval request to Slack and poll for response.
    In production, use Slack's Block Kit interactive messages.
    """
    print(f"[APPROVAL REQUIRED] Action: {action}, Params: {params}")
    print(f"Context: {context}")
    # Stub: auto-approve in test environments
    approval = os.getenv("AUTO_APPROVE", "false").lower() == "true"
    print(f"[APPROVAL] {'Approved' if approval else 'Denied'}")
    return approval

def tiered_execute_tool(tool_name: str, tool_input: dict, reasoning: str) -> str:
    if tool_name in TIER_0_ACTIONS:
        # Execute immediately
        return f"[EXECUTED] {tool_name}({tool_input})"
    elif tool_name in TIER_1_ACTIONS:
        approved = request_human_approval(tool_name, tool_input, reasoning)
        if approved:
            return f"[EXECUTED after approval] {tool_name}({tool_input})"
        else:
            return f"[BLOCKED] Human denied {tool_name}. Escalating to on-call."
    else:
        return f"[ERROR] Unknown action tier for {tool_name}"

def run_tiered_agent(alert: dict) -> str:
    tools = [
        {
            "name": "apply_terraform",
            "description": "Apply a Terraform plan to increase resource limits. TIER-1: requires human approval.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "plan_id": {"type": "string"},
                    "workspace": {"type": "string"},
                },
                "required": ["plan_id", "workspace"],
            },
        },
        {
            "name": "restart_pod",
            "description": "Restart a Kubernetes pod. TIER-0: autonomous.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "namespace": {"type": "string"},
                    "pod_name": {"type": "string"},
                },
                "required": ["namespace", "pod_name"],
            },
        },
    ]
    messages = [{"role": "user", "content": f"Incident: {alert}"}]
    last_reasoning = ""
    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )
        if response.stop_reason == "end_turn":
            for b in response.content:
                if b.type == "text":
                    return b.text
            return "Completed"
        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            results = []
            for b in response.content:
                if b.type == "text":
                    last_reasoning = b.text
                if b.type == "tool_use":
                    out = tiered_execute_tool(b.name, b.input, last_reasoning)
                    results.append({"type": "tool_result", "tool_use_id": b.id, "content": out})
            messages.append({"role": "user", "content": results})
